// HELPER: Find User by Referral Code (for commission logic)
const findUserByReferralCode = async (code: string) => {
  // Try direct lookup first
  const codeSnap = await getDoc(doc(db, 'referral_codes', code));
  if (codeSnap.exists()) {
      const userId = codeSnap.data().userId;
      const userSnap = await getDoc(doc(db, 'users', userId));
      if (userSnap.exists()) {
          return { ref: userSnap.ref, data: userSnap.data() as User, id: userId };
      }
  }

  // Fallback to query
  const q = query(collection(db, 'users'), where('referralCode', '==', code), limit(1));
  const snap = await getDocs(q);
  if (snap.empty) return null;
  return { ref: snap.docs[0].ref, data: snap.docs[0].data() as User, id: snap.docs[0].id };
};

export const purchasePackageFirestore = async (userId: string, pkgId: string, currentPackages: Package[]) => {
  console.log(`[Purchase] Start for user ${userId}, node ${pkgId}`);
  const pkg = currentPackages.find(p => p.id === pkgId);
  if (!pkg) throw new Error("Invalid Package Configuration");

  const userRef = doc(db, 'users', userId);

  // 1. Resolve Upline BEFORE transaction
  let uplineRefs: { ref: any, percentage: number, level: number, id: string }[] = [];
  try {
      // FETCH DYNAMIC REFERRAL SETTINGS
      const settingsRef = doc(db, 'system', 'settings');
      const settingsSnap = await getDoc(settingsRef);
      const settings = settingsSnap.exists() ? settingsSnap.data() as AppState['platformSettings'] : null;

      const isReferralEnabled = settings?.isReferralSystemEnabled !== false; // Default true if undefined
      const activeLevels = settings?.referralLevels && settings.referralLevels.length > 0 
          ? settings.referralLevels 
          : REF_LEVELS; // Fallback to constants if empty

      if (isReferralEnabled) {
          const userSnapBefore = await getDoc(userRef);
          if(userSnapBefore.exists()) {
              const userDataBefore = userSnapBefore.data() as User;
              let currentReferrerCode = userDataBefore.referredBy;

              // Iterate through the dynamic levels sorted by level index
              const sortedLevels = [...activeLevels].sort((a,b) => a.level - b.level);

              for (const levelConfig of sortedLevels) {
                  if (!currentReferrerCode) break;
                  const uplineUser = await findUserByReferralCode(currentReferrerCode);
                  if (uplineUser) {
                      uplineRefs.push({ 
                          ref: uplineUser.ref, 
                          percentage: levelConfig.percentage, 
                          level: levelConfig.level, 
                          id: uplineUser.id
                      });
                      currentReferrerCode = uplineUser.data.referredBy;
                  } else {
                      break;
                  }
              }
          }
      } else {
          console.log("[Purchase] Referral system is disabled by admin.");
      }
  } catch (err) {
      console.warn("[Purchase] Warning: Referral lookup failed (likely permission issues). Proceeding with purchase only.", err);
      uplineRefs = []; 
  }

  const activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  const activePkgsSnap = await getDocs(activePkgsQuery);
  const existingDocRef = activePkgsSnap.empty ? null : activePkgsSnap.docs[0].ref;
  let cost = pkg.minAmount;

  // 2. Execute MAIN Purchase Transaction (User focused only)
  await runTransaction(db, async (transaction) => {
    const userSnap = await transaction.get(userRef);
    if (!userSnap.exists()) throw new Error("User does not exist!");
    const userData = userSnap.data() as User;

    let isUpgrade = false;
    let currentData: UserPackage | null = null;

    if (existingDocRef) {
      const pkgSnap = await transaction.get(existingDocRef);
      if (pkgSnap.exists()) {
        currentData = pkgSnap.data() as UserPackage;
        if (currentData.packageId === pkgId) throw new Error("Plan already active.");
        if (pkg.minAmount <= currentData.amount) throw new Error("Downgrade not allowed.");
        cost = pkg.minAmount - currentData.amount;
        isUpgrade = true;
      }
    }

    if (userData.capitalBalance < cost) throw new Error(`Insufficient balance. Required: ${cost.toFixed(2)} USDT`);

    // Deduct Cost
    transaction.update(userRef, { capitalBalance: increment(-cost) });

    // Update/Create Package
    if (isUpgrade && existingDocRef && currentData) {
      transaction.update(existingDocRef, { packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now() });
    } else {
      const activePkgRef = doc(collection(db, 'activePackages'));
      transaction.set(activePkgRef, { id: activePkgRef.id, packageId: pkg.id, amount: pkg.minAmount, activatedAt: Date.now(), lastPayoutAt: Date.now(), isActive: true, totalEarned: 0, userId });
    }

    // Create Transaction
    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, { id: txRef.id, userId, type: TransactionType.PURCHASE, amount: cost, status: TransactionStatus.COMPLETED, timestamp: Date.now(), description: isUpgrade ? `Upgrade to ${pkg.name}` : `Node Activation: ${pkg.name}` });
  });

  // 3. Process Referral Commissions (Best Effort)
  if (uplineRefs.length > 0) {
      try {
          await runTransaction(db, async (transaction) => {
            for (const upline of uplineRefs) {
                // Ensure we can read the upline document before updating
                const upSnap = await transaction.get(upline.ref);
                if (upSnap.exists()) {
                    const commission = cost * (upline.percentage / 100);
                    if (commission > 0) {
                        // Credit the upline
                        transaction.update(upline.ref, {
                            profitBalance: increment(commission),
                            referralEarnings: increment(commission),
                            totalEarned: increment(commission)
                        });

                        // Transaction Record for Upline
                        const refTxRef = doc(collection(db, 'transactions'));
                        transaction.set(refTxRef, {
                            id: refTxRef.id,
                            userId: upline.id, // Use string ID from lookup
                            type: TransactionType.REFERRAL,
                            amount: commission,
                            status: TransactionStatus.COMPLETED,
                            timestamp: Date.now(),
                            description: `L${upline.level} Commission`
                        });

                        // GRANULAR TRACKING: If this is Level 1, update the specific referral record
                        if (upline.level === 1) {
                            const referralRecordRef = doc(db, 'referrals', userId);
                            const refRecordSnap = await transaction.get(referralRecordRef);
                            if (refRecordSnap.exists()) {
                                transaction.update(referralRecordRef, {
                                    totalCommissions: increment(commission)
                                });
                            }
                        }
                    }
                }
            }
          });
      } catch (err) {
          console.warn("[Purchase] Commission processing skipped due to permissions/error:", err);
      }
  }
};

export const processDailyRoiFirestore = async (settings: any, currentPackages: Package[], userId?: string) => {
  if (!settings.isRoiEnabled || settings.platformPaused) return;

  // Optimized Query: Only fetch specific user's packages if userId is provided
  let activePkgsQuery;
  if (userId) {
     activePkgsQuery = query(collection(db, 'activePackages'), where('userId', '==', userId), where('isActive', '==', true));
  } else {
     activePkgsQuery = query(collection(db, 'activePackages'), where('isActive', '==', true));
  }

  const activePkgsSnap = await getDocs(activePkgsQuery);
  const now = Date.now();
  const ONE_DAY_MS = 24 * 60 * 60 * 1000;

  for (const docSnap of activePkgsSnap.docs) {
    const ap = docSnap.data() as UserPackage;
    const pkg = currentPackages.find(p => p.id === ap.packageId);
    if (!pkg || pkg.isActive === false) continue;

    const lastPayout = ap.lastPayoutAt || ap.activatedAt;
    const timeDiff = now - lastPayout;

    // Check if at least 24 hours have passed
    if (timeDiff >= ONE_DAY_MS) {
        // Calculate exact number of payout cycles missed (Catch-Up Logic)
        const intervals = Math.floor(timeDiff / ONE_DAY_MS);

        if (intervals > 0) {
            const dailyPercent = settings.roiOverride || pkg.dailyRoi;
            const singleDayEarnings = ap.amount * (dailyPercent / 100);
            const totalEarnings = singleDayEarnings * intervals;

            // Calculate new lastPayoutAt based on missed intervals to prevent time drift
            // (e.g., if paid at 10:00 AM, next pay should be 10:00 AM next day, even if script runs at 10:05 AM)
            const newLastPayoutAt = lastPayout + (intervals * ONE_DAY_MS);

            await runTransaction(db, async (transaction) => {
                const userRef = doc(db, 'users', ap.userId);
                const userSnap = await transaction.get(userRef);
                if (!userSnap.exists()) return;

                transaction.update(userRef, { 
                    profitBalance: increment(totalEarnings), 
                    totalEarned: increment(totalEarnings) 
                });

                transaction.update(doc(db, 'activePackages', docSnap.id), { 
                    totalEarned: increment(totalEarnings), 
                    lastPayoutAt: newLastPayoutAt 
                });

                const txRef = doc(collection(db, 'transactions'));
                transaction.set(txRef, { 
                    id: txRef.id, 
                    userId: ap.userId, 
                    type: TransactionType.ROI, 
                    amount: totalEarnings, 
                    status: TransactionStatus.COMPLETED, 
                    timestamp: now, 
                    description: `Daily Yield (x${intervals}) from ${pkg.name}` 
                });
            });
        }
    }
  }
};

export const performWhatsappShareTask = async (userId: string) => {
  const settingsRef = doc(db, 'system', 'settings');
  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const settingsSnap = await transaction.get(settingsRef);
    const userSnap = await transaction.get(userRef);

    if (!userSnap.exists()) throw new Error("User not found");
    const user = userSnap.data() as User;

    const settings = settingsSnap.exists() ? settingsSnap.data() : {};
    const taskConfig = settings.whatsappConfig as WhatsappTaskConfig | undefined;

    // 1. Check if Enabled
    if (!taskConfig || !taskConfig.enabled) {
      throw new Error("Task is currently disabled by administrator.");
    }

    // 2. Check Lifetime Limit
    const currentShares = user.whatsappShares || 0;
    if (currentShares >= taskConfig.maxLifetimeShares) {
      throw new Error(`Maximum lifetime shares (${taskConfig.maxLifetimeShares}) reached.`);
    }

    // 3. Check Cooldown
    const lastShare = user.lastWhatsappShare || 0;
    const now = Date.now();
    const cooldownMs = taskConfig.cooldownHours * 60 * 60 * 1000;
    const timeSinceLast = now - lastShare;

    if (timeSinceLast < cooldownMs) {
      const hoursRemaining = Math.ceil((cooldownMs - timeSinceLast) / (60 * 60 * 1000));
      throw new Error(`Cooldown active. Try again in ${hoursRemaining} hours.`);
    }

    // 4. Execute Reward
    transaction.update(userRef, {
      whatsappShares: increment(1),
      lastWhatsappShare: now,
      profitBalance: increment(taskConfig.rewardAmount),
      totalEarned: increment(taskConfig.rewardAmount)
    });

    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, {
      id: txRef.id,
      userId,
      type: TransactionType.TASK_REWARD,
      amount: taskConfig.rewardAmount,
      status: TransactionStatus.COMPLETED,
      timestamp: now,
      description: `Task Reward: WhatsApp Share`
    });
  });
};

import React, { useState, useEffect, useRef } from 'react';
import { User, TransactionStatus, TransactionType, PaymentSettings, BankAccount, AppState } from '../types.ts';
import { QRCodeCanvas } from 'qrcode.react';
import { processExternalDeposit, requestFiatDeposit, requestFiatWithdrawal, fetchBankAccountsFirestore } from '../store.ts';
import { doc, getDoc } from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { db } from '../firebase.ts';

interface WalletProps {
  user: User;
  paymentSettings?: PaymentSettings;
  onDepositSim: () => void;
  onWithdrawRequest: (amount: number, address: string) => void;
}

const Wallet: React.FC<WalletProps> = ({ user, paymentSettings, onDepositSim, onWithdrawRequest }) => {
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [withdrawAddress, setWithdrawAddress] = useState(user.withdrawalAddress || '');
  const [isSyncing, setIsSyncing] = useState(false);

  // Platform Settings
  const [settings, setSettings] = useState<AppState['platformSettings'] | null>(null);
  const [bankAccounts, setBankAccounts] = useState<BankAccount[]>([]);

  // Payment Gateway State (Crypto)
  const [depositAmount, setDepositAmount] = useState<string>('');
  const [activePayment, setActivePayment] = useState<any>(null);
  const [paymentStatus, setPaymentStatus] = useState<string>('waiting'); 
  const [isGeneratingPayment, setIsGeneratingPayment] = useState(false);
  const [paymentError, setPaymentError] = useState<string | null>(null);

  // Fiat Deposit State
  const [activeTab, setActiveTab] = useState<'CRYPTO' | 'FIAT'>('CRYPTO');
  const [withdrawTab, setWithdrawTab] = useState<'CRYPTO' | 'FIAT'>('CRYPTO');

  const [fiatDepositAmountNgn, setFiatDepositAmountNgn] = useState('');
  const [selectedBankId, setSelectedBankId] = useState('');
  const [proofImage, setProofImage] = useState<string>('');
  const [isSubmittingFiat, setIsSubmittingFiat] = useState(false);

  // Fiat Withdrawal State
  const [fiatWithdrawAmountUsdt, setFiatWithdrawAmountUsdt] = useState('');
  const [fiatUserBank, setFiatUserBank] = useState({ bankName: '', accountName: '', accountNumber: '' });

  // Refs for polling management
  const pollTimeoutRef = useRef<number | null>(null);
  const isMounted = useRef(true);

  const usePaymentGateway = paymentSettings?.isEnabled;

  useEffect(() => {
    return () => { isMounted.current = false; stopPolling(); };
  }, []);

  useEffect(() => {
    const loadData = async () => {
        const settingsSnap = await getDoc(doc(db, 'system', 'settings'));
        if (settingsSnap.exists()) {
            setSettings(settingsSnap.data() as AppState['platformSettings']);
        }
        const banks = await fetchBankAccountsFirestore();
        setBankAccounts(banks.filter(b => b.isActive));
    };
    loadData();
  }, []);

  const stopPolling = () => {
    if (pollTimeoutRef.current) {
        clearTimeout(pollTimeoutRef.current);
        pollTimeoutRef.current = null;
    }
  };

  const handleManualSync = async () => {
    setIsSyncing(true);
    await onDepositSim();
    setIsSyncing(false);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 500 * 1024) {
        alert("File too large. Please select an image under 500KB.");
        return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
        setProofImage(reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleFiatDeposit = async () => {
      const amount = parseFloat(fiatDepositAmountNgn);
      if (!amount || amount <= 0 || !selectedBankId || !proofImage || !settings) {
          alert("Please complete all fields and upload proof.");
          return;
      }
      setIsSubmittingFiat(true);
      try {
          await requestFiatDeposit(user.id, amount, settings.depositRateNgn, proofImage, selectedBankId);
          alert("Deposit request submitted! Awaiting admin approval.");
          setFiatDepositAmountNgn('');
          setProofImage('');
          setSelectedBankId('');
      } catch (err: any) {
          alert(err.message);
      } finally {
          setIsSubmittingFiat(false);
      }
  };

  const handleFiatWithdrawal = async () => {
      const amount = parseFloat(fiatWithdrawAmountUsdt);
      if (!amount || amount <= 0 || !fiatUserBank.accountNumber || !settings) {
          alert("Please check all fields.");
          return;
      }
      setIsSubmittingFiat(true);
      try {
          await requestFiatWithdrawal(user.id, amount, settings.withdrawalRateNgn, fiatUserBank);
          alert("Withdrawal request submitted! Funds will be sent after review.");
          setFiatWithdrawAmountUsdt('');
      } catch (err: any) {
          alert(err.message);
      } finally {
          setIsSubmittingFiat(false);
      }
  };

  const generatePayment = async () => {
    const amount = parseFloat(depositAmount);
    if (!amount || amount <= 0 || !paymentSettings?.apiKey) {
        setPaymentError("Invalid amount or missing API configuration.");
        return;
    }

    setIsGeneratingPayment(true);
    setPaymentError(null);
    setPaymentStatus('waiting');

    try {
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = 'https://api.nowpayments.io/v1/payment';

        const payload: any = {
            price_amount: amount,
            price_currency: 'usd',
            pay_currency: 'usdttrc20', // Enforced TRC20
            order_description: `Deposit User:${user.id}`
        };

        const response = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            method: 'POST',
            headers: {
                'x-api-key': paymentSettings.apiKey,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData.message || `API Error: ${response.statusText}`);
        }

        const data = await response.json();

        if (data.pay_address && data.payment_id) {
            setActivePayment(data);
            pollStatus(data.payment_id);
        } else {
            setPaymentError("Gateway failed to generate address. Please try again.");
        }
    } catch (err: any) {
        console.error("Payment Gen Error:", err);
        setPaymentError(err.message || "Connection failed. Please check your internet.");
    } finally {
        if(isMounted.current) setIsGeneratingPayment(false);
    }
  };

  const pollStatus = async (paymentId: string) => {
    if (!isMounted.current) return;

    try {
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = `https://api.nowpayments.io/v1/payment/${paymentId}`;

        const res = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            headers: { 'x-api-key': paymentSettings!.apiKey }
        });

        if (!res.ok) throw new Error("Status check failed");

        const data = await res.json();
        const status = data.payment_status;

        if(isMounted.current) setPaymentStatus(status);

        if (['finished', 'confirmed', 'sending'].includes(status)) {
            await handlePaymentSuccess(data);
            return; // Stop polling
        }

        if (status === 'expired' || status === 'failed') {
            setPaymentError("Transaction expired or failed. Please create a new deposit.");
            stopPolling();
            return;
        }

        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);

    } catch (e) { 
        console.debug("Poll failed (retrying...):", e); 
        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);
    }
  };

  const handlePaymentSuccess = async (data: any) => {
    stopPolling();
    try {
        const verifiedAmount = data.pay_amount || data.price_amount || parseFloat(depositAmount); 
        await processExternalDeposit(user.id, verifiedAmount, data.payment_id);
        alert(`Deposit of ${verifiedAmount} USDT confirmed successfully!`);
        if(isMounted.current) {
            setActivePayment(null);
            setDepositAmount('');
            setPaymentStatus('waiting');
        }
    } catch (e) {
        console.error("Credit error", e);
        setPaymentError("Payment confirmed but failed to update balance. Contact support with ID: " + data.payment_id);
    }
  };

  const getStatusDisplay = () => {
    switch(paymentStatus) {
        case 'waiting': return { text: 'Waiting for Funds...', color: 'text-app-muted', icon: 'fa-spinner fa-spin' };
        case 'confirming': return { text: 'Confirming on Blockchain...', color: 'text-blue-500', icon: 'fa-circle-notch fa-spin' };
        case 'confirmed': 
        case 'sending':
        case 'finished': return { text: 'Payment Successful!', color: 'text-green-500', icon: 'fa-check-circle' };
        case 'expired': return { text: 'Expired', color: 'text-red-500', icon: 'fa-times-circle' };
        default: return { text: paymentStatus.toUpperCase(), color: 'text-app-text', icon: 'fa-info-circle' };
    }
  };

  const statusInfo = getStatusDisplay();
  const selectedBank = bankAccounts.find(b => b.id === selectedBankId);

  return (
    <div className="max-w-7xl mx-auto space-y-24 pb-24 lg:pb-0">
      <div className="flex flex-col gap-4">
        <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">My<br/>Wallet.</h1>
        <p className="serif italic text-2xl text-app-muted max-w-xl">
          Secure multi-channel funding and withdrawal system.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-px bg-app-border border border-app-border">

        {/* Deposit Section */}
        <div className="bg-app-bg p-12 lg:p-20 space-y-12">
          <div className="flex items-center justify-between flex-wrap gap-4">
            <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">
                Add Funds
            </h2>
            <div className="flex gap-2">
                <button onClick={() => setActiveTab('CRYPTO')} className={`px-4 py-1 text-[9px] font-black uppercase tracking-widest border border-app-border transition-colors ${activeTab === 'CRYPTO' ? 'bg-app-accent text-app-accent-text' : 'text-app-muted hover:text-app-text'}`}>Crypto</button>
                {settings?.fiatDepositEnabled && (
                    <button onClick={() => setActiveTab('FIAT')} className={`px-4 py-1 text-[9px] font-black uppercase tracking-widest border border-app-border transition-colors ${activeTab === 'FIAT' ? 'bg-app-accent text-app-accent-text' : 'text-app-muted hover:text-app-text'}`}>Bank (NGN)</button>
                )}
            </div>
          </div>

          {activeTab === 'CRYPTO' ? (
              usePaymentGateway ? (
                // NowPayments Flow
                <div className="space-y-8">
                    {!activePayment ? (
                        <div className="space-y-6 animate-in fade-in">
                            <div className="p-6 bg-app-surface border border-app-border space-y-2">
                            <p className="text-[10px] font-black uppercase text-app-muted tracking-widest">TRC20 Gateway</p>
                            <p className="text-xs text-app-text/60 leading-relaxed font-medium">
                                Secure automated crypto deposit. Funds are credited instantly after blockchain confirmation.
                            </p>
                            </div>
                            <div className="space-y-2 group">
                                <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Amount (USD)</label>
                                <input 
                                    type="number" 
                                    value={depositAmount} 
                                    onChange={(e) => setDepositAmount(e.target.value)}
                                    className="w-full bg-transparent border-b border-app-border py-4 text-4xl font-black mono text-app-text outline-none focus:border-app-accent transition-colors"
                                    placeholder="100.00"
                                />
                            </div>
                            {paymentError && <p className="text-xs text-red-500 font-bold uppercase animate-pulse">{paymentError}</p>}
                            <button 
                                onClick={generatePayment}
                                disabled={isGeneratingPayment || !depositAmount}
                                className="w-full py-6 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-[0.4em] hover:opacity-90 transition-all flex items-center justify-center gap-4 disabled:opacity-50"
                            >
                                {isGeneratingPayment ? 'Generating...' : 'Deposit Funds'}
                            </button>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center gap-8 py-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            {/* Payment Status UI */}
                            <div className={`w-full p-4 border border-app-border flex items-center justify-center gap-3 ${paymentStatus === 'expired' ? 'bg-red-500/10' : 'bg-app-surface'}`}>
                                <i className={`fa-solid ${statusInfo.icon} ${statusInfo.color}`}></i>
                                <span className={`text-xs font-black uppercase tracking-widest ${statusInfo.color}`}>{statusInfo.text}</span>
                            </div>

                            {paymentStatus !== 'expired' && (
