Here are the complete **Firestore Security Rules** designed specifically for your application's architecture.

These rules bridge the gap between security and the client-side logic (transactions, ROI calculation, and node purchases) currently implemented in your frontend code.

### How to Apply
1. Go to your **Firebase Console**.
2. Navigate to **Firestore Database** > **Rules**.
3. Replace the entire content with the code below.
4. Click **Publish**.

```firestore
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // =========================================================
    // HELPER FUNCTIONS
    // =========================================================

    // Check if user is logged in
    function isAuthenticated() {
      return request.auth != null;
    }

    // Check if the user is accessing their own data
    function isOwner(userId) {
      return isAuthenticated() && request.auth.uid == userId;
    }

    // Check if the user is an Admin
    // We check the 'isAdmin' flag on the user document OR if they are the root admin in system status
    function isAdmin() {
      return isAuthenticated() && (
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true ||
        get(/databases/$(database)/documents/system/status).data.rootAdmin == request.auth.uid
      );
    }

    // =========================================================
    // COLLECTION RULES
    // =========================================================

    // 1. USERS
    // Users need read/write access to their own profile for client-side ROI/Purchasing logic
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isOwner(userId); // Account creation
      allow update: if isOwner(userId) || isAdmin(); // Balance updates, Profile settings
    }

    // 2. PACKAGES (Nodes)
    // Publicly readable so the landing page and dashboard can display them
    match /packages/{packageId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // 3. ACTIVE PACKAGES (User's purchased nodes)
    match /activePackages/{packageId} {
      allow read: if resource.data.userId == request.auth.uid || isAdmin();
      // Client-side purchase logic creates these
      allow create: if request.resource.data.userId == request.auth.uid;
      // Client-side ROI logic updates 'lastPayoutAt' and 'totalEarned'
      allow update: if resource.data.userId == request.auth.uid || isAdmin();
    }

    // 4. TRANSACTIONS
    // Ledger of all movements
    match /transactions/{txId} {
      allow read: if resource.data.userId == request.auth.uid || isAdmin();
      // Users create Withdrawal requests and Payment Gateway deposits
      allow create: if request.resource.data.userId == request.auth.uid || isAdmin();
      // Only Admins should update status (e.g., PENDING -> COMPLETED)
      allow update: if isAdmin();
    }

    // 5. SYSTEM SETTINGS (Global Config)
    match /system/settings {
      allow read: if true; // Needed for Maintenance Mode check & Exchange Rates
      allow write: if isAdmin();
    }

    // 6. PAYMENT SETTINGS (API Keys)
    match /system/payments {
      allow read: if isAuthenticated(); // Wallet component needs the Public Key
      allow write: if isAdmin();
    }

    // 7. SYSTEM STATUS (Root Admin ID)
    match /system/status {
      allow read: if true;
      allow write: if isAuthenticated(); // Initial app setup
    }

    // 8. BANKS (Fiat Banks)
    match /system_banks/{bankId} {
      allow read: if isAuthenticated(); // Users need to see where to deposit
      allow write: if isAdmin();
    }

    // 9. FIAT REQUESTS (Manual Bank Deposit/Withdrawal)
    match /fiat_requests/{requestId} {
      allow read: if resource.data.userId == request.auth.uid || isAdmin();
      allow create: if request.resource.data.userId == request.auth.uid;
      allow update: if isAdmin(); // Admin approves/rejects
    }

    // 10. REFERRAL CODES
    // Public read needed to resolve code during signup
    match /referral_codes/{code} {
      allow read: if true;
      allow write: if isAuthenticated(); // Created during user signup
    }

    // 11. REFERRALS (Downline Data)
    match /referrals/{docId} {
      // User can read their own record
      allow read: if resource.data.userId == request.auth.uid || isAdmin();

      // Allow querying referrals where 'referredBy' matches the user's code
      // (This fixes the "My Downline" list permission error)
      allow list: if isAuthenticated() && (
        resource.data.referredBy == get(/databases/$(database)/documents/users/$(request.auth.uid)).data.referralCode || 
        isAdmin()
      );

      allow create: if isAuthenticated();
      allow update: if isAdmin();
    }

    // 12. GIVEAWAY POOLS
    match /giveawayPools/{poolId} {
      allow read: if isAuthenticated();
      allow write: if isAdmin();
    }

    // 13. GIVEAWAY CLAIMS
    match /giveawayClaims/{claimId} {
      allow read: if resource.data.userId == request.auth.uid || isAdmin();
      allow create: if request.resource.data.userId == request.auth.uid;
    }

    // 14. VAULT (Private Keys)
    // STRICTLY ADMIN ONLY - Never allow public read
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

