        {/* Withdrawal Section */}
        <div className="bg-app-surface p-12 lg:p-20 space-y-12">
          <div className="flex items-center justify-between flex-wrap gap-4">
            <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">Withdraw</h2>
