                     </div>

                     <div className="space-y-2">
                        <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Proof of Payment</label>
                        <input 
                            type="file" 
                            accept="image/*"
                            onChange={handleImageUpload}
